{
  "children": [
    {
      "name": "ParseAndValidateCommand",
      "purpose": "Parse the input JSON and validate the command field",
      "behavior": "Extract command and message_data from input; check command is one of send, history, create_channel, join; return error if invalid",
      "boundary": {
        "in_scope": ["input parsing", "command validation"],
        "out_of_scope": ["message_data validation", "business logic"]
      },
      "semantic_inputs": [
        {"name": "input", "description": "JSON with command and message_data", "source": "parent input"}
      ],
      "semantic_outputs": [
        {"name": "validated_command", "description": "valid command string", "consumer": "parent"},
        {"name": "message_data", "description": "extracted message data object", "consumer": "parent"}
      ],
      "preconditions": ["input is valid JSON"],
      "postconditions": ["command is one of the allowed values"],
      "guarantees": ["returns error if command invalid"],
      "composition_role": "validate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "SendMessage",
      "purpose": "Handle send command: validate membership, store message, update last_seen",
      "behavior": "Check user is member of channel via channels store; create message entry in messages store; update channel's last_seen timestamp",
      "boundary": {
        "in_scope": ["membership check", "message storage", "last_seen update"],
        "out_of_scope": ["other commands", "history retrieval"]
      },
      "semantic_inputs": [
        {"name": "message_data", "description": "object with content, channel_id, user_id", "source": "parent input"},
        {"name": "channels", "description": "channel data store", "source": "internal leaf access"},
        {"name": "messages", "description": "message data store", "source": "internal leaf access"}
      ],
      "semantic_outputs": [
        {"name": "send_result", "description": "success or error response", "consumer": "parent"}
      ],
      "preconditions": ["command is send", "message_data has required fields"],
      "postconditions": ["message stored", "last_seen updated"],
      "guarantees": ["only if user is member"],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "GetHistory",
      "purpose": "Handle history command: retrieve last 100 messages from channel",
      "behavior": "Query messages store for channel_id, sort by timestamp descending, limit to 100",
      "boundary": {
        "in_scope": ["message retrieval", "sorting", "limiting"],
        "out_of_scope": ["membership validation", "message storage"]
      },
      "semantic_inputs": [
        {"name": "message_data", "description": "object with channel_id", "source": "parent input"},
        {"name": "messages", "description": "message data store", "source": "internal leaf access"}
      ],
      "semantic_outputs": [
        {"name": "history_result", "description": "list of messages or error", "consumer": "parent"}
      ],
      "preconditions": ["command is history", "channel exists"],
      "postconditions": ["returns up to 100 messages sorted by timestamp desc"],
      "guarantees": ["no side effects"],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "CreateChannel",
      "purpose": "Handle create_channel command: create channel with unique name, set creator as member",
      "behavior": "Check channel name uniqueness in channels store; create new channel entry with creator as first member",
      "boundary": {
        "in_scope": ["name uniqueness check", "channel creation", "member initialization"],
        "out_of_scope": ["message storage", "history"]
      },
      "semantic_inputs": [
        {"name": "message_data", "description": "object with channel_name, user_id", "source": "parent input"},
        {"name": "channels", "description": "channel data store", "source": "internal leaf access"}
      ],
      "semantic_outputs": [
        {"name": "create_result", "description": "success with channel_id or error", "consumer": "parent"}
      ],
      "preconditions": ["command is create_channel", "channel_name not empty"],
      "postconditions": ["new channel created", "creator added as member"],
      "guarantees": ["channel name unique"],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "JoinChannel",
      "purpose": "Handle join command: add user to channel's member list",
      "behavior": "Check channel exists; add user_id to channel's members array if not already present",
      "boundary": {
        "in_scope": ["channel existence check", "member addition"],
        "out_of_scope": ["channel creation", "message operations"]
      },
      "semantic_inputs": [
        {"name": "message_data", "description": "object with channel_id, user_id", "source": "parent input"},
        {"name": "channels", "description": "channel data store", "source": "internal leaf access"}
      ],
      "semantic_outputs": [
        {"name": "join_result", "description": "success or error response", "consumer": "parent"}
      ],
      "preconditions": ["command is join", "channel exists"],
      "postconditions": ["user added to channel members"],
      "guarantees": ["no duplicate membership"],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "FormatResponse",
      "purpose": "Format the final output JSON with success, data, and message fields",
      "behavior": "Take result from child operation and wrap in standard response format",
      "boundary": {
        "in_scope": ["response formatting"],
        "out_of_scope": ["business logic", "data access"]
      },
      "semantic_inputs": [
        {"name": "operation_result", "description": "result from the executed child", "source": "parent"},
        {"name": "error", "description": "error message if any", "source": "parent"}
      ],
      "semantic_outputs": [
        {"name": "output", "description": "JSON with success, data, message", "consumer": "parent"}
      ],
      "preconditions": ["operation_result or error is set"],
      "postconditions": ["output is valid JSON"],
      "guarantees": ["consistent response structure"],
      "composition_role": "aggregate",
      "stop_decompose": false,
      "stop_reason": ""
    }
  ],
  "decomposition_rationale": "The parent ChatApp handles four distinct commands. Each command is decomposed into its own child function that performs the specific business logic. ParseAndValidateCommand handles input validation upfront, and FormatResponse standardizes the output. The parent orchestrates by selecting the appropriate child based on the command.",
  "orchestration_model": "conditional",
  "dataflow_sketch": [
    {"from": "parent", "to": "ParseAndValidateCommand", "data": "input", "note": "parse and validate command"},
    {"from": "ParseAndValidateCommand", "to": "parent", "data": "validated_command, message_data", "note": "return parsed data"},
    {"from": "parent", "to": "SendMessage", "data": "message_data", "note": "if command is send"},
    {"from": "parent", "to": "GetHistory", "data": "message_data", "note": "if command is history"},
    {"from": "parent", "to": "CreateChannel", "data": "message_data", "note": "if command is create_channel"},
    {"from": "parent", "to": "JoinChannel", "data": "message_data", "note": "if command is join"},
    {"from": "SendMessage", "to": "parent", "data": "send_result", "note": "return result"},
    {"from": "GetHistory", "to": "parent", "data": "history_result", "note": "return result"},
    {"from": "CreateChannel", "to": "parent", "data": "create_result", "note": "return result"},
    {"from": "JoinChannel", "to": "parent", "data": "join_result", "note": "return result"},
    {"from": "parent", "to": "FormatResponse", "data": "operation_result or error", "note": "format final output"},
    {"from": "FormatResponse", "to": "parent", "data": "output", "note": "return formatted response"}
  ]
}
